import json, pathlib, sys, math, itertools
from collections import defaultdict
sys.path.append('/app/task_file/scripts')
from cost_model import CostModel
cm=CostModel(64)
root=pathlib.Path('/app/task_file/input_data')

def build(reqs, max_group, max_diff, lat_guard, shape_seq):
    # keep requests with singleton lat > lat_guard singleton
    singles=[]
    groups=defaultdict(list)
    single_lat={}
    for r in reqs:
        s=((r['prompt_len']+63)//64)*64
        lat=cm.batch_metrics([r])['latencies'][0]+8
        single_lat[r['request_id']]=lat
        if lat>lat_guard:
            singles.append(r)
        else:
            groups[s].append(r)
    plan=[]; bid=0
    shape={'seq_align':shape_seq,'heads_align':32,'hidden_align':4096}
    for r in singles:
        bid+=1
        plan.append({'request_id':r['request_id'],'batch_id':f'b-{bid:05d}','shape':shape})
    for s,rs in groups.items():
        rs=sorted(rs, key=lambda r:(r['gen_len'], r['prompt_len'], r['request_id']))
        cur=[]; min_g=None; max_g=None
        def flush(chunk):
            nonlocal bid, plan
            if not chunk: return
            bid+=1
            batch_id=f'b-{bid:05d}'
            for r in chunk:
                plan.append({'request_id':r['request_id'],'batch_id':batch_id,'shape':shape})
        for r in rs:
            g=r['gen_len']
            if not cur:
                cur=[r]; min_g=max_g=g
            elif len(cur)<max_group and max(max_g,g)-min(min_g,g)<=max_diff:
                cur.append(r); min_g=min(min_g,g); max_g=max(max_g,g)
            else:
                flush(cur); cur=[r]; min_g=max_g=g
        flush(cur)
    return plan

thresholds={
 'requests_bucket_1.jsonl': {'cost':3.0e11,'pad_ratio':0.055,'p95_latency_ms':2.1e6,'sequential_timecost':2.7e8,'shape_seq':2048},
