}
for name in thresholds:
    reqs=[json.loads(l) for l in open(root/name)]
    req_map={r['request_id']:r for r in reqs}
    th=thresholds[name]
    best=[]
    for max_group in [2,3,4,5,6,8,12,16,24,32]:
      for max_diff in [0,1,2,4,8,12,16,24,32,48,64,96,128]:
        for lat_guard in [0,5e4,1e5,1.5e5,2e5,3e5,5e5,8e5,1e6,1.5e6,2e6]:
          plan=build(reqs,max_group,max_diff,lat_guard,th['shape_seq'])
          m=cm.plan_metrics(req_map,plan)
          ok=all(m[k]<=th[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost'])
          if ok:
            print('PASS',name,max_group,max_diff,lat_guard,{k:round(m[k],4) for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']},'batches',len({p['batch_id'] for p in plan}))
            raise SystemExit
          best.append((sum(max(0,m[k]-th[k])/th[k] for k in ['cost','pad_ratio','p95_latency_ms','sequential_timecost']),max_group,max_diff,lat_guard,m,len({p['batch_id'] for p in plan})))
    best.sort(key=lambda x:x[0])
    print('BEST',name)
